// AI 처리가 필요한 영상 필터링 (description/comment 직접 매칭 없는 영상)
var videosResp = $('Get Active Videos').first().json;
var vpsResp = $input.first().json;

var videos = (videosResp && videosResp.list) ? videosResp.list : [];
var allVPs = (vpsResp && vpsResp.list) ? vpsResp.list : [];

// description/comment VPs가 있는 video_id 수집
var directVideoIds = {};
for (var i = 0; i < allVPs.length; i++) {
  var vp = allVPs[i];
  if (vp.source === 'description' || vp.source === 'comment') {
    directVideoIds[vp.video_id] = true;
  }
}

// AI 처리 대상: 직접 URL 매칭 없는 영상만
var toProcess = [];
for (var j = 0; j < videos.length; j++) {
  var v = videos[j];
  if (!directVideoIds[v.video_id]) {
    toProcess.push(v);
  }
}

return [{ json: { videos: toProcess, count: toProcess.length } }];

// 영상 배열을 개별 아이템으로 변환 (SplitInBatches 입력용)
var videos = $input.first().json.videos || [];
if (videos.length === 0) return [];
return videos.map(function(v) { return { json: v }; });

// Gemini API 프롬프트 구성
var v = $input.first().json;
var title = v.title || '';
var desc = (v.description || '').substring(0, 600);
var tagsArr = [];
try { tagsArr = JSON.parse(v.tags || '[]'); } catch(e) { tagsArr = []; }
var matchedCat = v.matched_category || '';

var prompt = '당신은 한국 공예 재료 쇼핑몰 상품 매칭 전문가입니다.\n\n다음 YouTube 영상 정보에서 영상에서 사용된 핵심 재료명을 추출해 주세요.\n\n영상 제목: ' + title + '\n';
if (matchedCat) prompt += '감지된 카테고리: ' + matchedCat + '\n';
if (tagsArr.length > 0) prompt += '태그: ' + tagsArr.slice(0, 8).join(', ') + '\n';
if (desc) prompt += '영상 설명(일부): ' + desc + '\n';
prompt += '\n규칙:\n';
prompt += '1. 상품명으로 검색 가능한 정확한 재료명 추출\n';
prompt += '2. 예: "UV레진", "실리콘 몰드", "소이왁스", "LED 천스탠드", "압화 꽃 세트", "탈포기"\n';
prompt += '3. 철자 주의: 탠 vs 텐, 탈포기 vs 달포기 등 정확한 상품 철자 사용\n';
prompt += '4. 최대 5개 키워드 추출\n';
prompt += '5. "만들기", "영상", "강좌", "DIY" 등 일반 단어 제외\n';
prompt += '\nJSON으로만 응답하세요 (다른 텍스트 없이):\n';
prompt += '{"keywords": ["키워드1", "키워드2"], "category": "압화|레진|캔들|석고|비즈|기타"}';

return [{ json: { video_id: v.video_id, title: v.title, prompt: prompt } }];

// Gemini 응답 파싱 + 상품 점수 계산 + deactivate/insert 배열 구성
var geminiResp = $input.first().json;
var buildData = $('Build Prompt').first().json;
var productsResp = $('Get All Products').first().json;
var vpsResp = $('Get All VPs').first().json;

var videoId = buildData.video_id;
var allProducts = (productsResp && productsResp.list) ? productsResp.list : [];
var allVPs = (vpsResp && vpsResp.list) ? vpsResp.list : [];

// Gemini 응답 파싱 (error 또는 정상 응답 모두 처리)
var keywords = [];
var aiCategory = '';
try {
  var candidates = (geminiResp && geminiResp.candidates) ? geminiResp.candidates : [];
  if (candidates.length > 0) {
    var text = '';
    if (candidates[0].content && candidates[0].content.parts && candidates[0].content.parts[0]) {
      text = candidates[0].content.parts[0].text || '';
    }
    // JSON 블록 추출 (```json ... ``` 또는 순수 JSON)
    var jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      var parsed = JSON.parse(jsonMatch[0]);
      keywords = (parsed.keywords || []).filter(function(k) { return k && k.length >= 2; });
      aiCategory = parsed.category || '';
    }
  }
} catch(e) { keywords = []; }

// 키워드가 없으면 기존 VP 그대로 유지 (아무것도 변경 안 함)
if (keywords.length === 0) {
  return [{ json: { video_id: videoId, keywords: [], deactivateBody: [], insertBody: [], skip: true } }];
}

// 기존 keyword/ai VP 비활성화 대상 (is_active=false 로 변경)
var deactivateBody = [];
for (var i = 0; i < allVPs.length; i++) {
  var vp = allVPs[i];
  if (vp.video_id === videoId && (vp.source === 'keyword' || vp.source === 'ai') && vp.is_active !== false) {
    deactivateBody.push({ Id: vp.Id, is_active: false });
  }
}

// 상품 점수 계산 (AI 키워드 매칭)
var scored = [];
for (var j = 0; j < allProducts.length; j++) {
  var prod = allProducts[j];
  var pname = (prod.product_name || '').toLowerCase();
  var score = 0;
  for (var k = 0; k < keywords.length; k++) {
    var kw = (keywords[k] || '').toLowerCase();
    // 전체 키워드 매칭 (최고 점수)
    if (kw.length >= 2 && pname.indexOf(kw) >= 0) score += 5;
    // 키워드 내 개별 단어 매칭 (부분 점수)
    var parts = kw.split(/\s+/);
    for (var p = 0; p < parts.length; p++) {
      if (parts[p].length >= 2 && pname.indexOf(parts[p]) >= 0) score += 2;
    }
  }
  // AI가 감지한 카테고리와 상품명 일치시 보너스
  if (aiCategory && pname.indexOf(aiCategory.toLowerCase()) >= 0) score += 1;
  if (score > 0) scored.push({ score: score, prod: prod });
}
scored.sort(function(a, b) { return b.score - a.score; });
var top4 = scored.slice(0, 4);

// 삽입할 AI VP 레코드 구성
var insertBody = [];
for (var t = 0; t < top4.length; t++) {
  var mp = top4[t];
  insertBody.push({
    video_id: videoId,
    branduid: String(mp.prod.branduid || ''),
    product_name: mp.prod.product_name || '',
    product_price: mp.prod.price || 0,
    product_image: mp.prod.image_url || '',
    product_url: mp.prod.product_url || ('/shop/shopdetail.html?branduid=' + mp.prod.branduid),
    source: 'ai',
    confidence: 'medium',
    match_score: mp.score,
    display_order: t + 1,
    is_active: true,
    matched_at: new Date().toISOString()
  });
}

return [{ json: { video_id: videoId, keywords: keywords, aiCategory: aiCategory, deactivateBody: deactivateBody, insertBody: insertBody, skip: false } }];
